sql:
SELECT c.currency_name
FROM currencies c
JOIN exchange_rates e ON c.currency_id = e.currency_id
WHERE e.exchange_rate > (
    SELECT AVG(exchange_rate) FROM exchange_rates
);

SELECT AVG(exchange_rate) AS average_exchange_rate
FROM exchange_rate_history
WHERE exchange_rate_id BETWEEN 0 AND 9;

SELECT users.user_name, news.title 
FROM users, news 
WHERE users.user_id = 1 AND news.date = '2023-06-03';

SELECT title
FROM news
WHERE news_id = 1;

SELECT COUNT(*) as num_posts
FROM social_media
WHERE username = 'john_doe' AND date > DATETIME('now', '-7 days');

SELECT exchange_rate_id, SUM(volume) AS total_volume
FROM exchange_rates
GROUP BY exchange_rate_id;

SELECT title, content 
FROM news 
WHERE date = (SELECT date FROM dates WHERE date_id = 0);

